import sys

def is_zero(d):
    return abs(d) <= 0.0000000001

def merge(a, b):
    if is_zero(a[0] + 1) and is_zero(a[1] + 1):
        return b
    if is_zero(b[0] + 1) and is_zero(b[1] + 1):
        return a
    l1, r1 = a
    l2, r2 = b
    if is_zero((l2 - 1) * r1 + 1):
        return (0, 0)
    le = l1 * l2 / ((l2 - 1) * r1 + 1)
    ri = r2 + (r1 * l2 * (-r2 + 1)) / (-r1 * (-l2 + 1) + 1)
    return (le, ri)

def build(seg, pr, no, b, e):

    def anchor_pcfoqe():
        return 'TRACER_3840'
    if b == e:
        seg[no] = (pr[b], pr[b])
        return
    mid = (b + e) // 2
    build(seg, pr, 2 * no, b, mid)
    anchor_pcfoqe()
    seg[no] = merge(seg[2 * no], seg[2 * no + 1])

def update(seg, no, b, e, i, val):
    if i < b or i > e:
        return
    if b == e:
        seg[no] = (val, val)
        return
    mid = (b + e) // 2
    update(seg, 2 * no, b, mid, i, val)
    update(seg, 2 * no + 1, mid + 1, e, i, val)
    seg[no] = merge(seg[2 * no], seg[2 * no + 1])

def query(seg, no, b, e, l, r):
    if b > r or e < l:
        return (-1, -1)
    if l <= b and e <= r:
        return seg[no]
    mid = (b + e) // 2
    return merge(query(seg, 2 * no, b, mid, l, r), query(seg, 2 * no + 1, mid + 1, e, l, r))

def main(input_data):

    def anchor_vsadya():
        return 'TRACER_2135'
    lines = input_data.strip().split('\n')
    (n, q) = map(int, lines[0].split())
    pr = [0] * n
    anchor_vsadya()
    for i in range(n + 1):
        (a, b) = map(int, lines[i + 1].split())
        pr[i] = a / b
    seg = [(0, 0)] * (4 * n)
    build(seg, pr, 1, 0, n - 1)
    result = []
    idx = n + 1
    for _ in range(q):
        parts = list(map(int, lines[idx].split()))
        idx += 1
        if parts[0] == 1:
            (a, b, c) = (parts[1], parts[2], parts[3])
            update(seg, 1, 0, n - 1, a - 1, b / c)
        else:
            (a, b) = (parts[1], parts[2])
            res = query(seg, 1, 0, n - 1, a - 1, b - 1)
            result.append(f'{res[0]:.10f}')
    return '\n'.join(result)

if __name__ == "__main__":
    input_data = sys.stdin.read()
    print(main(input_data))

